INSERT INTO `home_sectors` (`id`, `title`, `description`, `content`, `image_path`, `link`, `tag`, `stats`, `order`, `is_active`, `slug`, `icon`, `created_at`, `updated_at`) VALUES
(1, 'Education', 'Empowering the next generation through state-of-the-art educational infrastructure and student-centric learning hubs.', '<h3>Building the Future of Education</h3><p>We invest in building smart classrooms, digital libraries, and modern school campuses that make quality education accessible to everyone. Our focus is on creating environments that foster innovation and holistic growth.</p><ul><li>Smart Classroom Infrastructure</li><li>Vocational Training Centers</li><li>Scholarship Support Programs</li></ul>', 'home_sectors/r0GvMuu5NYYaoadwXJcUPI79MolJLUUYFGPKDh1h.jpg', NULL, 'Social Impact', '{\"yield\":\"High\",\"asset_class\":\"Social\",\"transparency\":\"100%\",\"exit_window\":\"Ongoing\"}', 1, 1, 'education', 'fas fa-graduation-cap', '2026-04-02 12:02:14', '2026-04-04 12:43:35'),
(2, 'Social Welfare', 'Comprehensive community support programs designed to uplift the marginalized and ensure basic human dignity for all.', '<h3>Driving Social Transformation</h3><p>Our social welfare initiatives target the root causes of poverty and inequality. We work with local communities to implement sustainable development projects that provide immediate relief and long-term stability.</p>', 'home_sectors/4dXEu5IERPCJBrz4AQI7ozWfb7cgkyQ0s3eNJ4Uf.webp', NULL, 'Community', '{\"yield\":\"Impact\",\"asset_class\":\"Welfare\",\"transparency\":\"Verified\",\"exit_window\":\"Perpetual\"}', 2, 1, 'social-welfare', 'fas fa-hands-helping', '2026-04-02 12:02:14', '2026-04-04 12:44:32'),
(3, 'Anath Ashram (Old Age Home)', 'Providing a dignified and loving environment for the elderly and orphaned, ensuring they feel valued and cared for.', '<h3>A Home Away From Home</h3><p>Our Anath Ashram and Old Age Homes are designed to provide more than just shelter. We offer a community of care, medical support, and emotional well-being for those who need it most.</p>', 'home_sectors/7ZPn6sYh1Qk7hSjOnUc3EXFyRfGniz45cr0sAZgg.webp', NULL, 'Compassion', '{\"yield\":\"Blessings\",\"asset_class\":\"Residential\",\"transparency\":\"Open\",\"exit_window\":\"Life-long\"}', 3, 1, 'anath-ashram', 'fas fa-home', '2026-04-02 12:02:14', '2026-04-04 12:47:25'),
(4, 'Community Hall', 'Modern, multi-purpose spaces where communities come together to celebrate, learn, and grow.', '<h3>The Heart of the Community</h3><p>Our community halls serve as vibrant hubs for social gatherings, workshops, and local events. Built with modern amenities, they are the go-to spaces for fostering community spirit.</p>', 'home_sectors/pFZQVlBg6fW1Mmm2tCqOWvluLXRxXoq5a76FVclr.jpg', NULL, 'Public Asset', '{\"yield\":\"Self-Sustain\",\"asset_class\":\"Commercial\",\"transparency\":\"Public\",\"exit_window\":\"Fixed\"}', 4, 1, 'community-hall', 'fas fa-users-viewfinder', '2026-04-02 12:02:14', '2026-04-04 12:57:43'),
(5, 'Skill Development Program', 'Bridging the skill gap by providing market-ready vocational training and certifications to the youth.', '<h3>Empowering through Skills</h3><p>In a rapidly changing job market, we equip individuals with the technical and soft skills needed to succeed. Our programs are industry-linked and focus on immediate employability.</p>', 'home_sectors/BmMiEJybEY6rzrTokAxg9OqVJFChWUHnPGoPKvxh.webp', NULL, 'Economic Growth', '{\"yield\":\"Job Ready\",\"asset_class\":\"Human Cap\",\"transparency\":\"Audit\",\"exit_window\":\"Annual\"}', 5, 1, 'skill-development', 'fas fa-microchip', '2026-04-02 12:02:14', '2026-04-04 12:50:07'),
(6, 'Women Empowerment', 'Fostering independence and leadership through financial literacy, entrepreneurship training, and legal support for women.', '<h3>Unleashing Potential</h3><p>We believe that when you empower a woman, you empower a nation. Our programs provide the resources, mentorship, and support systems women need to lead and succeed.</p>', 'home_sectors/UifXuguiHc2zByDC25H921JZIlLET4SNVbicAVPX.jpg', NULL, 'Equality', '{\"yield\":\"Multiplier\",\"asset_class\":\"Social\",\"transparency\":\"Traceable\",\"exit_window\":\"Generational\"}', 6, 1, 'women-empowerment', 'fas fa-hand-holding-heart', '2026-04-02 12:02:14', '2026-04-04 12:50:52'),
(7, 'Environmental Protection', 'Protecting our planet through tree plantation drives, waste management solutions, and renewable energy adoption.', '<h3>A Greener Tomorrow</h3><p>We are dedicated to preserving the environment for future generations. Our projects focus on restoring ecosystems and promoting sustainable living practices in urban and rural areas.</p>', 'home_sectors/WwzyHF1T6t5OakBrGeZDCOIlQePlsEBRk4A71VVS.jpg', NULL, 'Sustainability', '{\"yield\":\"Green\",\"asset_class\":\"Natural\",\"transparency\":\"Public\",\"exit_window\":\"Decades\"}', 7, 1, 'environmental-protection', 'fas fa-seedling', '2026-04-02 12:02:14', '2026-04-04 12:51:25'),
(8, 'Child Welfare', 'Ensuring a bright future for every child through nutrition, healthcare, and protection from exploitation.', '<h3>Nurturing Every Child</h3><p>Our child welfare programs provide a safety net for children in need. We focus on early childhood development, protection, and ensuring every child has the opportunity to dream.</p>', 'home_sectors/BrroEdIsl1OsEcynTM8JdxOiZSB1Le0LTvoJZdNV.webp', NULL, 'Future First', '{\"yield\":\"Nurture\",\"asset_class\":\"Human Cap\",\"transparency\":\"Strict\",\"exit_window\":\"Ongoing\"}', 8, 1, 'child-welfare', 'fas fa-baby-carriage', '2026-04-02 12:02:14', '2026-04-04 12:52:16'),
(9, 'Health and Medical', 'Direct medical aid, rural health clinics, and emergency response systems to ensure healthcare for the underserved.', '<h3>Accessible Healthcare</h3><p>We bring institutional healthcare to those who cannot afford or access it. From mobile clinics to emergency support, our goal is to ensure that health is a right, not a privilege.</p>', 'home_sectors/X2t3eu9f4f8CsJJNqJ52gFhBRMMUkSNL6UnbSxsd.jpg', NULL, 'Life Saving', '{\"yield\":\"Vital\",\"asset_class\":\"Medical\",\"transparency\":\"Live\",\"exit_window\":\"Immediate\"}', 9, 1, 'health-and-medical', 'fas fa-stethoscope', '2026-04-02 12:02:14', '2026-04-04 12:53:12');
