(151, 29, 'श्रीमद्भगवद्गीता में कुल कितने अध्याय हैं?,16,18,20,24,1,1', '[\"\\u0917\\u0940\\u0924\\u093e \\u0915\\u093e \\u0909\\u092a\\u0926\\u0947\\u0936 \\u0915\\u093f\\u0938\\u0928\\u0947 \\u0926\\u093f\\u092f\\u093e?,\\u092c\\u094d\\u0930\\u0939\\u094d\\u092e\\u093e,\\u0936\\u093f\\u0935,\\u0915\\u0943\\u0937\\u094d\\u0923,\\u0907\\u0902\\u0926\\u094d\\u0930,2,1\",\"\\u0917\\u0940\\u0924\\u093e \\u0915\\u093e \\u0909\\u092a\\u0926\\u0947\\u0936 \\u0915\\u093f\\u0938\\u0947 \\u0926\\u093f\\u092f\\u093e \\u0917\\u092f\\u093e?,\\u0905\\u0930\\u094d\\u091c\\u0941\\u0928,\\u092d\\u0940\\u0937\\u094d\\u092e,\\u0926\\u0941\\u0930\\u094d\\u092f\\u094b\\u0927\\u0928,\\u0915\\u0930\\u094d\\u0923,0,1\",\"\\u092e\\u0939\\u093e\\u092d\\u093e\\u0930\\u0924 \\u092f\\u0941\\u0926\\u094d\\u0927 \\u0915\\u0939\\u093e\\u0901 \\u0939\\u0941\\u0906 \\u0925\\u093e?,\\u0926\\u094d\\u0935\\u093e\\u0930\\u0915\\u093e,\\u0915\\u0941\\u0930\\u0941\\u0915\\u094d\\u0937\\u0947\\u0924\\u094d\\u0930,\\u092e\\u0925\\u0941\\u0930\\u093e,\\u0915\\u093e\\u0936\\u0940,1,1\",\"\\u0917\\u0940\\u0924\\u093e \\u092e\\u0947\\u0902 \\u0915\\u0930\\u094d\\u092e\\u092f\\u094b\\u0917 \\u0915\\u093e \\u0909\\u092a\\u0926\\u0947\\u0936 \\u0915\\u093f\\u0938 \\u0905\\u0927\\u094d\\u092f\\u093e\\u092f \\u092e\\u0947\\u0902 \\u092a\\u094d\\u0930\\u092e\\u0941\\u0916 \\u0939\\u0948?,2,3,6,12,1,1\"]', 0, 1, '2026-04-10 11:54:05', '2026-04-10 11:54:05'),
