(174, 32, 'भारत का नया संसद भवन किस वर्ष उद्घाटित किया गया?,2021,2022,2023,2024,2,1', '[\"\\u0939\\u093e\\u0932 \\u0939\\u0940 \\u092e\\u0947\\u0902 G20 \\u0936\\u093f\\u0916\\u0930 \\u0938\\u092e\\u094d\\u092e\\u0947\\u0932\\u0928 2023 \\u0915\\u093e \\u0906\\u092f\\u094b\\u091c\\u0928 \\u0915\\u0939\\u093e\\u0901 \\u0939\\u0941\\u0906?,\\u092e\\u0941\\u0902\\u092c\\u0908,\\u0928\\u0908 \\u0926\\u093f\\u0932\\u094d\\u0932\\u0940,\\u091c\\u092f\\u092a\\u0941\\u0930,\\u0915\\u094b\\u0932\\u0915\\u093e\\u0924\\u093e,1,1\",\"\\u092d\\u093e\\u0930\\u0924 \\u0915\\u0947 \\u0935\\u0930\\u094d\\u0924\\u092e\\u093e\\u0928 \\u092a\\u094d\\u0930\\u0927\\u093e\\u0928\\u092e\\u0902\\u0924\\u094d\\u0930\\u0940 \\u0915\\u094c\\u0928 \\u0939\\u0948\\u0902?,\\u0928\\u0930\\u0947\\u0902\\u0926\\u094d\\u0930 \\u092e\\u094b\\u0926\\u0940,\\u0930\\u093e\\u0939\\u0941\\u0932 \\u0917\\u093e\\u0902\\u0927\\u0940,\\u0905\\u092e\\u093f\\u0924 \\u0936\\u093e\\u0939,\\u0930\\u093e\\u091c\\u0928\\u093e\\u0925 \\u0938\\u093f\\u0902\\u0939,0,1\",\"\\u091a\\u0902\\u0926\\u094d\\u0930\\u092f\\u093e\\u0928-3 \\u092e\\u093f\\u0936\\u0928 \\u0915\\u093f\\u0938 \\u0917\\u094d\\u0930\\u0939\\/\\u0909\\u092a\\u0917\\u094d\\u0930\\u0939 \\u0938\\u0947 \\u0938\\u0902\\u092c\\u0902\\u0927\\u093f\\u0924 \\u0939\\u0948?,\\u092e\\u0902\\u0917\\u0932,\\u0936\\u0941\\u0915\\u094d\\u0930,\\u091a\\u0902\\u0926\\u094d\\u0930\\u092e\\u093e,\\u0938\\u0942\\u0930\\u094d\\u092f,2,1\",\"\\u0939\\u093e\\u0932 \\u0939\\u0940 \\u092e\\u0947\\u0902 \\u0915\\u093f\\u0938 \\u0926\\u0947\\u0936 \\u0928\\u0947 \\u092d\\u093e\\u0930\\u0924 \\u0915\\u0947 \\u0938\\u093e\\u0925 \\u201cExercise Yudh Abhyas\\u201d \\u0915\\u093f\\u092f\\u093e?,\\u0930\\u0942\\u0938,\\u0905\\u092e\\u0947\\u0930\\u093f\\u0915\\u093e,\\u091a\\u0940\\u0928,\\u091c\\u093e\\u092a\\u093e\\u0928,1,1\"]', 0, 1, '2026-04-11 08:02:35', '2026-04-11 08:02:35'),
